class Program
{
    static void Main()
    {
        string csv = "apple,banana,cherry";
        string[] parts = csv.Split(',');
        Console.WriteLine(parts.Length);   // 3
        Console.WriteLine(parts[1]);       // banana

        string joined = String.Join(" | ", parts);
        Console.WriteLine(joined);  // apple | banana | cherry

        string words = "hello   world";
        string[] split = words.Split(' ', StringSplitOptions.RemoveEmptyEntries);
        Console.WriteLine(split.Length);  // 2
    }
}

