class Program
{
    static void Main()
    {
        var sb = new System.Text.StringBuilder();
        for (int i = 0; i < 5; i++)
        {
            sb.Append(i);
            sb.Append(' ');
        }
        Console.WriteLine(sb.ToString().Trim());  // 0 1 2 3 4

        var sb2 = new System.Text.StringBuilder("Hello World");
        sb2.Replace("World", "C#");
        sb2.Insert(0, ">> ");
        Console.WriteLine(sb2.ToString());  // >> Hello C#
    }
}

