class Program
{
    static void Main()
    {
        string a = "hello";
        string b = "HELLO";
        Console.WriteLine(a == b);           // False
        Console.WriteLine(a.Equals(b, StringComparison.OrdinalIgnoreCase)); // True

        char[] chars = a.ToCharArray();
        Array.Reverse(chars);
        string reversed = new string(chars);
        Console.WriteLine(reversed);         // olleh
    }
}

